urlset:
{%- for sitemap_entry in entries %}
  {%- if not sitemap_entry.extra or not sitemap_entry.extra.skip_sitemap %}

  {{ sitemap_entry.permalink | escape_xml | safe }}
      {%- if sitemap_entry.updated %}
  {{ sitemap_entry.updated }}
      {%- elif sitemap_entry.date %}
  {{ sitemap_entry.date }}
      {%- endif %}

  {%- endif %}
{%- endfor %}
